module RefModule (
  input clk,
  input reset,
  input in,
  output reg state);parameter IDLE = 1'b0, ACTIVE = 1'b1;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
		if (reset)
			state <= IDLE;
		else
			case (state)
				IDLE: if (in) state <= ACTIVE;
				ACTIVE: state <= ACTIVE;
			endcase
	end
endmodule
